def utc_now_compact() -> str:
    return datetime.now(timezone.utc).strftime("%Y%m%dT%H%M%SZ")


def sha256_json(payload: Mapping[str, Any]) -> str:
    data = json.dumps(payload, sort_keys=True, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
    return hashlib.sha256(data).hexdigest()


def _json_load(path: Path) -> dict[str, Any] | None:
    try:
        raw = path.read_text(encoding="utf-8-sig")
        loaded = json.loads(raw)
    except Exception:
        return None
    return loaded if isinstance(loaded, dict) else None


def _is_ready_payload(payload: Mapping[str, Any], patch_id: str | None = None, version: str | None = None) -> bool:
    if patch_id is not None and payload.get("patch_id") != patch_id:
        return False
    if version is not None and payload.get("patch_version") != version:
        return False
    if payload.get("status") != "READY":
        return False
    if payload.get("ok") is False:
        return False
    if int(payload.get("final_safety_violation_count", 0) or 0) != 0:
        return False
    for key in (
        "exchange_submit_performed",
        "network_order_submit_performed",
        "order_submit_performed",
        "paper_order_submit_performed",
        "runtime_start_command_executed",
        "runtime_start_command_execution_performed",
        "runtime_start_performed",
        "paper_runtime_start_performed",
        "runtime_process_started",
        "approved_for_live_real",
        "approved_for_exchange_submit",
    ):
        if payload.get(key) is True:
            return False
    return True


def find_latest_ready_report(reports_dir: str | Path, patch_id: str, version: str) -> tuple[Path | None, dict[str, Any] | None]:
    root = Path(reports_dir)
    if not root.exists():
        return None, None
    candidates = sorted(root.rglob(f"{patch_id}_*_ready.json"), key=lambda p: p.stat().st_mtime, reverse=True)
    candidates.extend(sorted(root.rglob(f"{patch_id.lower()}_*_ready.json"), key=lambda p: p.stat().st_mtime, reverse=True))
    for path in candidates:
        payload = _json_load(path)
        if payload is not None and _is_ready_payload(payload, patch_id=patch_id, version=version):
            return path, payload
    for path in sorted(root.rglob("*.json"), key=lambda p: p.stat().st_mtime, reverse=True):
        payload = _json_load(path)
        if payload is not None and _is_ready_payload(payload, patch_id=patch_id, version=version):
            return path, payload
    return None, None


def _rules(spec: Mapping[str, Any]) -> list[dict[str, Any]]:
    return [
        {"rule_id": f"{idx:02d}_{policy.lower().replace(' ', '_').replace('-', '_')[:80]}", "policy": policy, "ready": True}
        for idx, policy in enumerate(spec.get("rules", []), start=1)
    ]


